Using DecoratorsUsing the <code>subscribe()</code> method <pre><code>from pyventus import EventLinker

with EventLinker.on("StringEvent") as linker: # (1)!

    @linker.on_event
    def event_callback() -&gt; str:
        print("Event received!")
        return "Event succeeded!"

    @linker.on_success
    async def success_callback(msg: str) -&gt; None:
        print(msg)

    @linker.on_failure
    def failure_callback(exc: Exception) -&gt; None:
